const nonhub=b=>new Set((b.apps||[]).map(a=>a.toLowerCase()).filter(a=>!HUB.has(a)));
const toks=s=>new Set(String(s||'').toLowerCase().split(/[^a-z0-9]+/).filter(t=>t.length>2));
function jacc(a,b){ if(a.size===0&&b.size===0)return 0; let i=0; a.forEach(x=>{if(b.has(x))i++;}); const u=new Set([...a,...b]).size; return u?i/u:0; }
function declares(a,b){ const e=String(a.similitud||'').toLowerCase(); if(!e)return false; if(e.includes(String(b.nombre).toLowerCase()))return true; const bt=toks(b.nombre); if(!bt.size)return false; const et=toks(e); let ov=0; bt.forEach(t=>{if(et.has(t))ov++;}); return ov>=Math.max(2,bt.size-1); }
function sim(a,b){ const t=jacc(toks(a.nombre+' '+a.proposito+' '+(a.apps||[]).join(' ')), toks(b.nombre+' '+b.proposito+' '+(b.apps||[]).join(' ')))*100; const ap=jacc(nonhub(a),nonhub(b))*100; const blended=(1-W_APPS)*t+W_APPS*ap; if(declares(a,b)||declares(b,a)){ const na=nonhub(a), nb=nonhub(b); const sh=[...na].some(x=>nb.has(x)); return Math.max(blended, sh?DECL_STRONG:DECL_WEAK);} return blended; }

// --- clustering union-find ---
const parent=INV.map((_,i)=>i);
const find=x=>{ while(parent[x]!==x){ parent[x]=parent[parent[x]]; x=parent[x]; } return x; };
const union=(a,b)=>{ const ra=find(a), rb=find(b); if(ra!==rb) parent[Math.max(ra,rb)]=Math.min(ra,rb); };
for(let i=0;i<INV.length;i++) for(let j=i+1;j<INV.length;j++) if(sim(INV[i],INV[j])>=THRESHOLD) union(i,j);
const groups={}; INV.forEach((_,i)=>{ const r=find(i); (groups[r]=groups[r]||[]).push(i); });
const clusterSizeOf={}; Object.values(groups).forEach(g=>g.forEach(i=>clusterSizeOf[INV[i].id]=g.length));

// --- scoring ---
const FREQ={high:40,medium:25,low:10};
const ICX={api:10,email:12,file:18,database:25,ui_legacy:40,unknown:35};
const RVAL={high:30,medium:18,low:8}, RCX={high:25,medium:12,low:4};
function freqBucket(f){ f=String(f||'').toLowerCase(); if(/(diari|hora|minuto|intradia|tiempo real|evento)/.test(f))return 'high'; if(/(semanal|quincenal)/.test(f))return 'medium'; return 'low'; }
function known(b){ return (b.interacciones||[]).filter(i=>i!=='unknown'); }
function value(b,inDup){ let s=FREQ[freqBucket(b.frecuencia)]+RVAL[b.riesgo]; if(inDup)s+=30; return Math.min(s,100); }
function complexity(b){ const inter=(b.interacciones&&b.interacciones.length)?b.interacciones:['unknown']; let base=Math.max(...inter.map(i=>ICX[i]||35)); const extra=Math.max(known(b).length-1,0)*5; let s=base+extra+RCX[b.riesgo]+Math.min((b.dependencias||[]).length*5,20); return Math.min(s,100); }
function wave(v,c,manual){ if(manual)return 'ola_3'; if(v>=50&&c<=40)return 'ola_1'; if(v>=40&&c<=65)return 'ola_2'; return 'ola_3'; }
function classify(b,size){ const reasons=[]; let manual=false; if(b.riesgo==='high'&&(b.dependencias||[]).length>=3){ manual=true; reasons.push('Alto riesgo con '+b.dependencias.length+' dependencias: revisar manualmente.'); } const inter=new Set(known(b)); const big=size>=3; if(inter.size===0){ reasons.push('Interaccion no reconocida.'); return {target:'manual_review',reasons,manual:true}; } if(inter.has('ui_legacy')){ reasons.push('Depende de UI legacy: RPA selectivo.'); return {target:'rpa_selective',reasons,manual}; } if(big){ reasons.push('Variante en cluster grande: microservicio compartido.'); return {target:'microservice',reasons,manual}; } if(inter.has('database')){ reasons.push('Interaccion con BD: Python/Java a la medida.'); return {target:'custom_python_java',reasons,manual}; } reasons.push('Integracion API/archivo/email: candidato a n8n.'); return {target:'n8n',reasons,manual}; }

// --- ejecutar ---
const recs=INV.map(b=>{ const size=clusterSizeOf[b.id]||1; const inDup=size>=2; const c=classify(b,size); const v=value(b,inDup), cx=complexity(b); return { taskbot_id:b.id, taskbot:b.nombre, destino:c.target, ola:wave(v,cx,c.manual), valor:Math.round(v*10)/10, complejidad:Math.round(cx*10)/10, cluster_size:size, revision_manual:c.manual, razones:c.reasons }; });
const dupGroups=Object.values(groups).filter(g=>g.length>=2);
const byT=t=>recs.filter(r=>r.destino===t).length;
const byW=w=>recs.filter(r=>r.ola===w).length;
const variantes=dupGroups.reduce((a,g)=>a+g.length,0);
const summary={ total_taskbots:recs.length, grupos_consolidables:dupGroups.length,
  por_destino:{ n8n:byT('n8n'), microservice:byT('microservice'), custom_python_java:byT('custom_python_java'), rpa_selective:byT('rpa_selective'), manual_review:byT('manual_review') },
  por_ola:{ ola_1:byW('ola_1'), ola_2:byW('ola_2'), ola_3:byW('ola_3') } };
const headlines=[ variantes+' taskbots son variantes de '+dupGroups.length+' utilidades reutilizables.', summary.por_destino.n8n+' candidatos a n8n (API/archivo/email).', summary.por_destino.rpa_selective+' quedan en RPA selectivo por UI legacy.', summary.por_destino.microservice+' deberian ser microservicio/componente compartido.', summary.por_ola.ola_1+' entran en ola 1 (alto valor, baja complejidad).' ];
return [{ json:{ run_id:'n8n-cloud-'+Date.now(), summary, headlines, recommendations:recs } }];
